using MediatR;

namespace InventoryFlow.Application.Features.Inventory;

/// <summary>Describes common inventory movement command fields.</summary>
public interface IInventoryMovementCommand
{
    /// <summary>Gets the workspace identifier.</summary>
    Guid WorkspaceId { get; }
