12	    /// <inheritdoc />
13	    public async Task<InventoryMovement?> RecordAsync(Guid workspaceId, Guid warehouseId, Guid productId, InventoryMovementType type,
14	        decimal quantity, string idempotencyKey, DateTimeOffset occurredAtUtc, CancellationToken cancellationToken)
15	    {
16	        quantity = InventoryMovement.ValidateQuantity(quantity);
17	        idempotencyKey = InventoryMovement.NormalizeIdempotencyKey(idempotencyKey);
18	        if (!Enum.IsDefined(type)) throw new ArgumentOutOfRangeException(nameof(type));
19	
20	        var strategy = dbContext.Database.CreateExecutionStrategy();
21	        return await strategy.ExecuteAsync(async () =>
22	        {
23	            await using var transaction = await dbContext.Database.BeginTransactionAsync(IsolationLevel.Serializable, cancellationToken);
24	            var existing = await dbContext.InventoryMovements.SingleOrDefaultAsync(movement =>
25	                movement.WorkspaceId == workspaceId && movement.IdempotencyKey == idempotencyKey, cancellationToken);
26	            if (existing is not null)
27	            {
28	                await transaction.CommitAsync(cancellationToken);
29	                return existing;
30	            }
31	
32	            var warehouseExists = await dbContext.Warehouses.AnyAsync(warehouse => warehouse.Id == warehouseId &&
33	                warehouse.WorkspaceId == workspaceId && warehouse.ArchivedAtUtc == null, cancellationToken);
34	            var productExists = await dbContext.Products.AnyAsync(product => product.Id == productId &&
35	                product.WorkspaceId == workspaceId && product.ArchivedAtUtc == null, cancellationToken);
36	            if (!warehouseExists || !productExists)
37	            {
38	                await transaction.RollbackAsync(cancellationToken);
39	                return null;
40	            }
41	
42	            var balance = await dbContext.InventoryBalances.SingleOrDefaultAsync(item => item.WorkspaceId == workspaceId &&
43	                item.WarehouseId == warehouseId && item.ProductId == productId, cancellationToken);
44	            if (balance is null)
45	            {
46	                balance = new InventoryBalance(workspaceId, warehouseId, productId, 0m);
47	                dbContext.InventoryBalances.Add(balance);
48	            }
49	
50	            balance.Apply(type == InventoryMovementType.Receipt ? quantity : -quantity);
51	            var movement = new InventoryMovement(Guid.NewGuid(), workspaceId, warehouseId, productId, type, quantity,
52	                idempotencyKey, balance.Quantity, occurredAtUtc);
53	            dbContext.InventoryMovements.Add(movement);
54	            await dbContext.SaveChangesAsync(cancellationToken);
55	            await transaction.CommitAsync(cancellationToken);
56	            return movement;
57	        });
